#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define clear(a,b) memset(a,(b),sizeof(a))
using namespace std;
const int N=5e5+5,INF=0x3f3f3f3f;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
int a[N],deq[N],K[N],h,t,n;int dp[N];
inline double Cnt(int x,int y){return 1.0*a[y]+sqrt(x-y);}
inline void Solve()
{
	h=1,t=0;rep(1,n,i)
	{
		while(h<t&&Cnt(K[t-1],deq[t])<Cnt(K[t-1],i))t--;
		int l=i,r=(K[deq[t]]?K[deq[t]]:n),mid;int res=r+1;
		while(l<=r){mid=(l+r)>>1;(Cnt(mid,i)>Cnt(mid,deq[t]))?(r=mid-1,res=mid):l=mid+1;}
		K[t]=res;deq[++t]=i;while(h<t&&K[h]<=i)h++;dp[i]=max(dp[i],int(ceil(Cnt(i,deq[h]))));
	}
}
int main()
{
	n=read();rep(1,n,i)a[i]=read();clear(dp,-0x3f);
	Solve();rep(1,n>>1,i)swap(a[i],a[n-i+1]),swap(dp[i],dp[n-i+1]);Solve();
	drep(n,1,i)printf("%d\n",dp[i]-a[i]);
	return 0;
}
